{
  "terms": [
    {
      "term": "Atom",
      "simpleDefinition": "The smallest basic unit of matter, consisting of a central nucleus orbited by electrons.",
      "anchor": "The building block of every material in an electrical circuit.",
      "misconception": "Thinking an atom is a solid, unbreakable sphere rather than a collection of smaller particles."
    },
    {
      "term": "Nucleus",
      "simpleDefinition": "The dense center of an atom containing protons and neutrons.",
      "anchor": "The 'sun' at the center of the atomic solar system.",
      "misconception": "Believing the nucleus itself moves through a wire during electrical flow."
    },
    {
      "term": "Proton",
      "simpleDefinition": "A subatomic particle with a positive electrical charge, located in the nucleus.",
      "anchor": "Think 'P' for Positive.",
      "misconception": "Thinking protons are the charge carriers that move to create current."
    },
    {
      "term": "Electron",
      "simpleDefinition": "A tiny subatomic particle with a negative electrical charge that orbits the nucleus.",
      "anchor": "The 'moving parts' of electricity.",
      "misconception": "Thinking electrons are stationary or 'stuck' in one place within a conductor."
    },
    {
      "term": "Valence Shell",
      "simpleDefinition": "The outermost orbit or shell of an atom.",
      "anchor": "The 'exit door' where electrons leave or join the atom.",
      "misconception": "Believing all electron shells contribute equally to electrical conduction."
    },
    {
      "term": "Free Electron",
      "simpleDefinition": "An electron in the valence shell that has broken free from its parent atom to move through a material.",
      "anchor": "The 'drifter' that carries the electrical charge from one point to another.",
      "misconception": "Thinking free electrons travel at the speed of light through the cable."
    },
    {
      "term": "Conductor",
      "simpleDefinition": "A material that allows electricity to flow easily because it has many free electrons.",
      "anchor": "Copper or aluminum wiring.",
      "misconception": "Assuming all metals are equally good at conducting electricity."
    },
    {
      "term": "Insulator",
      "simpleDefinition": "A material that resists the flow of electricity because its electrons are tightly bound to their atoms.",
      "anchor": "The PVC plastic coating on a cable.",
      "misconception": "Believing that insulators contain no electrons at all."
    }
  ],
  "anchorPhrases": [
    "Electricity is the directed flow of free electrons.",
    "Opposite charges attract; like charges repel.",
    "Conductors have loosely bound valence electrons.",
    "Insulators have tightly bound valence electrons."
  ],
  "misconceptionTargets": [
    "Protons do not move through the circuit; only electrons flow.",
    "Insulators have electrons, they just aren't 'free' to move.",
    "The number of electrons in the valence shell determines if a material is a conductor or an insulator."
  ]
}

{
  "teachChecks": [
    {
      "title": "Atomic Structure",
      "basicQuestions": [
        {
          "questionText": "What is the name of the dense core at the center of an atom?",
          "answerGuidance": [
            "Nucleus"
          ],
          "hint": "This core contains the protons and neutrons.",
          "sourceTeachingPointIds": [
            1
          ]
        },
        {
          "questionText": "Which subatomic particle carries a positive electrical charge?",
          "answerGuidance": [
            "Proton"
          ],
          "hint": "Think 'P' for positive.",
          "sourceTeachingPointIds": [
            2
          ]
        },
        {
          "questionText": "What type of electrical charge does an electron carry?",
          "answerGuidance": [
            "Negative"
          ],
          "hint": "It is the opposite of a proton's charge.",
          "sourceTeachingPointIds": [
            4
          ]
        }
      ],
      "deeperQuestionText": "Why is the electron the primary particle involved in electrical flow rather than the proton?",
      "deeperAnswerGuidance": [
        "Electrons orbit the nucleus on the outside",
        "Protons are trapped in the stationary nucleus",
        "Electrons can break away from the atom",
        "The nucleus is a dense stationary core"
      ],
      "deeperSourceTeachingPointIds": [
        1,
        2,
        4
      ],
      "hint": "Consider the location of each particle within the atom's structure."
    },
    {
      "title": "The Valence Shell",
      "basicQuestions": [
        {
          "questionText": "What is the specific name for the outermost shell of an atom?",
          "answerGuidance": [
            "Valence shell"
          ],
          "hint": "This shell determines the electrical properties of the material.",
          "sourceTeachingPointIds": [
            6
          ]
        },
        {
          "questionText": "What determines the electrical properties of a material?",
          "answerGuidance": [
            "Number of valence electrons"
          ],
          "hint": "It depends on how many electrons are in the outer layer.",
          "sourceTeachingPointIds": [
            7
          ]
        },
        {
          "questionText": "How does a nearly full valence shell affect the electrons within it?",
          "answerGuidance": [
            "Tightly bound"
          ],
          "hint": "Think about how hard the atom holds onto them.",
          "sourceTeachingPointIds": [
            9
          ]
        }
      ],
      "deeperQuestionText": "If two different materials have different numbers of electrons in their outermost shell, how does this affect their ability to work in a circuit?",
      "deeperAnswerGuidance": [
        "It determines if they are conductors or insulators",
        "It dictates how easily electrons are removed",
        "It determines if they allow or resist electrical flow",
        "The shell stability dictates the reaction to electrical pressure"
      ],
      "deeperSourceTeachingPointIds": [
        7,
        8,
        9
      ],
      "hint": "Think about the difference between an empty-ish shell and a full-ish shell."
    },
    {
      "title": "Free Electron Theory",
      "basicQuestions": [
        {
          "questionText": "What is the term for a valence electron that has broken away from its parent atom?",
          "answerGuidance": [
            "Free electron"
          ],
          "hint": "These electrons are no longer attached to a specific atom.",
          "sourceTeachingPointIds": [
            10
          ]
        },
        {
          "questionText": "What is the definition of electrical current in terms of electron movement?",
          "answerGuidance": [
            "Directed flow of free electrons"
          ],
          "hint": "It is not just random movement; it is movement in a specific direction.",
          "sourceTeachingPointIds": [
            12
          ]
        },
        {
          "questionText": "What role do free electrons play in transporting energy through a circuit?",
          "answerGuidance": [
            "Charge carriers"
          ],
          "hint": "They 'carry' the charge from one point to another.",
          "sourceTeachingPointIds": [
            13
          ]
        }
      ],
      "deeperQuestionText": "Why is the presence of 'free' electrons specifically required for a material to be useful as a wire?",
      "deeperAnswerGuidance": [
        "Current is the movement of these electrons",
        "Without them breaking free no flow can occur",
        "They act as the medium for energy transport",
        "Bound electrons cannot drift through the material"
      ],
      "deeperSourceTeachingPointIds": [
        10,
        12,
        14
      ],
      "hint": "Consider what would happen if every electron stayed attached to its own atom."
    },
    {
      "title": "Properties of Conductors",
      "basicQuestions": [
        {
          "questionText": "How many electrons are typically found in the valence shell of a conductor?",
          "answerGuidance": [
            "1 to 3"
          ],
          "hint": "Conductors have a mostly empty outer shell.",
          "sourceTeachingPointIds": [
            16
          ]
        },
        {
          "questionText": "What term describes how electrons are held in the valence shell of a conductor?",
          "answerGuidance": [
            "Loosely bound"
          ],
          "hint": "This allows them to become free electrons easily.",
          "sourceTeachingPointIds": [
            17
          ]
        },
        {
          "questionText": "Which metal is most commonly used as a conductor in electrical installations?",
          "answerGuidance": [
            "Copper"
          ],
          "hint": "It is efficient, flexible, and used in most cables.",
          "sourceTeachingPointIds": [
            19
          ]
        }
      ],
      "deeperQuestionText": "How does having only one or two valence electrons make a metal like copper a good choice for wiring?",
      "deeperAnswerGuidance": [
        "The valence shell is mostly empty",
        "Electrons are loosely bound",
        "They become free electrons very easily",
        "It allows for a high density of charge carriers"
      ],
      "deeperSourceTeachingPointIds": [
        16,
        17,
        18
      ],
      "hint": "Relate the number of electrons to how easily they can move."
    },
    {
      "title": "Properties of Insulators",
      "basicQuestions": [
        {
          "questionText": "How many electrons are typically found in the valence shell of an insulator?",
          "answerGuidance": [
            "5 to 8"
          ],
          "hint": "Insulators have a nearly or completely full outer shell.",
          "sourceTeachingPointIds": [
            21
          ]
        },
        {
          "questionText": "What term describes how electrons are held in the valence shell of an insulator?",
          "answerGuidance": [
            "Tightly bound"
          ],
          "hint": "This prevents them from breaking free.",
          "sourceTeachingPointIds": [
            22
          ]
        },
        {
          "questionText": "Which specific plastic material is commonly used to insulate electrical cables?",
          "answerGuidance": [
            "PVC"
          ],
          "hint": "It stands for Polyvinyl Chloride.",
          "sourceTeachingPointIds": [
            24
          ]
        }
      ],
      "deeperQuestionText": "Why is it impossible for a material with a full valence shell to act as a conductor?",
      "deeperAnswerGuidance": [
        "Electrons are tightly bound to the nucleus",
        "No electrons can break free to move",
        "There are no charge carriers to create current",
        "The full shell prevents electron drift"
      ],
      "deeperSourceTeachingPointIds": [
        21,
        22,
        23
      ],
      "hint": "Think about the requirement for 'free' electrons to create current."
    }
  ]
}

{
  "integrative": {
    "title": "Integrative Close: Material Selection",
    "objective": "Synthesize electron theory with practical material selection by explaining the relationship between valence electrons and conductivity/insulation.",
    "retrievalTextLines": [
      "Copper is used for the internal conductor of a cable.",
      "PVC is used for the external insulating sheath.",
      "The behavior of these materials depends on their valence shells."
    ],
    "questionText": "Explain how the difference in the number of valence electrons between copper and PVC determines their specific roles in a standard electrical cable.",
    "answerGuidance": [
      "Copper has few valence electrons (1-3) that are loosely bound.",
      "These easily become free electrons to carry electrical current.",
      "PVC has many valence electrons (5-8) that are tightly bound.",
      "This prevents the movement of electrons, making it an effective insulator."
    ],
    "hint": "Focus on how the 'grip' the nucleus has on its outer electrons differs between a material that allows flow and one that blocks it."
  }
}

